mapper.select:
select la.id, la.phone, la.name, la.identification_number, la.apartment_id, la.room_id, la.lease_start_date, la.lease_end_date, la.lease_term_id, la.rent, la.deposit, la.payment_type_id, la.status, la.source_type, la.additional_info, ai.id as ai_id, ai.name as ai_name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone as ai_phone, ai.is_release as ai_is_release, ri.id as ri_id, ri.room_number, ri.rent as ri_rent, ri.apartment_id as ri_apartment_id, ri.is_release as ri_is_release, pt.id as pt_id, pt.name as pt_name, pt.pay_month_count, pt.additional_info as pt_additional_info, lt.id as lt_id, lt.month_count, lt.unit from lease_agreement as la left join apartment_info as ai on la.apartment_id = ai.id and ai.is_deleted = 0 left join room_info as ri on la.room_id = ri.id and ri.is_deleted = 0 left join payment_type as pt on la.payment_type_id = pt.id and pt.is_deleted = 0 left join lease_term as lt on la.lease_term_id = lt.id and lt.is_deleted = 0
la.is_deleted = 0
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
and la.apartment_id = #{queryVo.apartmentId}
and ri.room_number = #{queryVo.roomNumber}
and la.name like concat('%', #{queryVo.name}, '%')
and la.phone like concat('%', #{queryVo.phone}, '%')
